1	export type Cell = readonly [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survives = (isAlive: boolean, neighborCount: number): boolean =>
12	  (isAlive && neighborCount === 2) || neighborCount === 3;
13	
14	export function nextGeneration(cells: readonly Cell[]): Cell[] {
15	  const aliveKeys = new Set(cells.map(cellKey));
16	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
17	
18	  for (const [x, y] of cells) {
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const neighbor: Cell = [x + dx, y + dy];
21	      const key = cellKey(neighbor);
22	      const existing = neighborCounts.get(key);
23	      if (existing) {
24	        existing.count++;
25	      } else {
26	        neighborCounts.set(key, { cell: neighbor, count: 1 });
27	      }
28	    }
29	  }
30	
31	  const result: Cell[] = [];
32	  for (const [key, { cell, count }] of neighborCounts) {
33	    if (survives(aliveKeys.has(key), count)) {
34	      result.push(cell);
35	    }
36	  }
37	  return result;
38	}
